import React, { Component } from 'react';
import { Link, withRouter } from 'react-router-dom';
import { connect } from 'react-redux';
import PropTypes from 'prop-types';
import axios from 'axios';
import s from '../Auth.module.scss';
import $ from 'jquery';
import Icon from '../../../Icons/base';

import ReactLoading from 'react-loading';

class PasswordResetRequest extends Component {

    constructor(props) {
        super(props);
        this.state = {
            email: "",
            success: false,
            error_general: null,
            waiting: false
        };

        this.handleInputChange = this.handleInputChange.bind(this);
        this.submitForm = this.submitForm.bind(this);

        if (props.auth.isAuthenticated) {
            props.history.push('/');
        }
    }

    handleInputChange(e) {
        const current_target = [e.target.name].toString();
        this.setState({ [e.target.name]: e.target.value, error_general: null });
    }

    triggerFocus(e) {
        $(e.target).parent().addClass(s['form-group--active']);
    }

    removeFocus(e) {
        if (e.target.value == "") {
            $(e.target).parent().removeClass(s['form-group--active']);
        }
    }

    submitForm(e) {
        e.preventDefault();
        this.setState({ waiting: true });
        axios.post(`${process.env.REACT_APP_GLOBAL_API_URL}/api/auth/password-recovery/request`, { email: this.state.email }).then(res => {
            if(res.data['status'] === undefined || res.data['status'] !== 1) {
                this.setState({ error_general: res.data['general'], waiting: false })
            } else {
                this.setState({ success: true, waiting: false });
            }
        })
    }

    render() {

        const { error_general, success, waiting } = this.state;

        return (
            <div className={s.background}>
                <div className={s.form}>
                    <div className={s.header}>
                        <h3>Password reset</h3>
                        <Link to="/">Artly</Link>
                    </div>
                    <form onSubmit={this.submitForm} autoComplete="off">
                        {success ? <div className={[s['form-group__response'], s['form-group__response--success']].join(' ')}>
                            <div className={s['form-group__response--flex']}>
                                <Icon name="checkmarkcircle"/>
                                <p>We've sent you password reset request email.</p>
                            </div>
                        </div> :<> 
                        <div className={s['form-group']}>
                            <input
                                type="email"
                                name="email"
                                onChange={this.handleInputChange}
                                onFocus={this.triggerFocus}
                                onBlur={this.removeFocus}
                                value={this.state.email}
                                className='bs-input'
                            />
                            <span>Email address</span>
                            {(error_general !== null) ? <p className={s['form-error']}>{error_general}</p> : ''}
                        </div>
                        <div className={[s['form-group'], s['form-group__submit']].join(' ')}>
                            <button type="submit" disabled={this.state.waiting}>{waiting ? <ReactLoading type="bars" color="#ffffff" height="auto" width="auto" /> : "Reset now"}</button>
                        </div>
                        <div className={s['form-group__final']}>
                            <p>However remember password? <Link to="/login">Log in.</Link></p>
                        </div></>}
                    </form>
                </div>
            </div>
        )
    }
}

PasswordResetRequest.propTypes = {
    auth: PropTypes.object,
    history: PropTypes.object.isRequired
};

const mapStateToProps = (state) => ({
    auth: state.auth
});

export default withRouter(connect(mapStateToProps)(PasswordResetRequest));
